const { Manifold, CrossSection, label, setCircularSegments } = api;
setCircularSegments(48);

// ---------------------------------------------------------------------------
// HOT AIR BALLOON
//   - Gored envelope (6 vertical gores: red / yellow / blue, twice) on top
//   - A mouth ring + small burner at the envelope base
//   - An OPEN GAP crossed by 4 visible suspension ropes
//   - A wicker basket HANGING clearly BELOW the envelope
// Z-up. Everything overlaps by >=0.5 units so it unions into one solid.
// ---------------------------------------------------------------------------

// ---- Envelope: a sphere stretched taller, sliced into vertical gores --------
const envR = 10; // sphere radius (widest half-width)
const envSZ = 1.35; // vertical stretch
const envCZ = 26; // center height; sphere spans z = 12.5 .. 39.5
const baseSphere = Manifold.sphere(envR, 48).scale([1, 1, envSZ]).translate([0, 0, envCZ]);

// 6 gores, colors cycling red/yellow/blue twice around the balloon.
const goreColors = ['red', 'yellow', 'blue', 'red2', 'yellow2', 'blue2'];
const numGores = 6;
const anglePer = 360 / numGores;
const wedgeR = 22; // larger than the sphere so the wedge fully spans it
const wedgeZlo = 10,
  wedgeZhi = 42; // covers the whole envelope height

const gores = [];
for (let i = 0; i < numGores; i++) {
  const angle = i * anglePer;
  const halfAngle = anglePer / 2;
  const a1 = (angle - halfAngle) * Math.PI / 180;
  const a2 = (angle + halfAngle) * Math.PI / 180;
  const pts = [
    [0, 0, wedgeZlo],
    [0, 0, wedgeZhi],
    [wedgeR * Math.cos(a1), wedgeR * Math.sin(a1), wedgeZlo],
    [wedgeR * Math.cos(a1), wedgeR * Math.sin(a1), wedgeZhi],
    [wedgeR * Math.cos(a2), wedgeR * Math.sin(a2), wedgeZlo],
    [wedgeR * Math.cos(a2), wedgeR * Math.sin(a2), wedgeZhi],
  ];
  const wedge = Manifold.hull(pts.map(p => Manifold.sphere(0.01, 4).translate(p)));
  gores.push(label(baseSphere.intersect(wedge), goreColors[i]));
}
const envelope = Manifold.union(gores);

// ---- Mouth ring + burner at the envelope base ------------------------------
const mouthZ = 14.0;
const ringOuter = 6.0,
  ringInner = 4.4,
  ringH = 1.6;
const mouthRing = label(
  Manifold.cylinder(ringH, ringOuter, ringOuter, 48)
  .subtract(Manifold.cylinder(ringH + 1, ringInner, ringInner, 48).translate([0, 0, -0.5]))
  .translate([0, 0, mouthZ - ringH / 2]),
  'rope' // share the dark "rope" color
);
const burner = label(
  Manifold.cylinder(2.4, 1.1, 1.4, 24).translate([0, 0, mouthZ - 1.0]),
  'rope'
);

// ---- Basket: a wicker box hanging well BELOW the envelope -------------------
const basketTopZ = 7.0,
  basketBotZ = 1.0;
const basketH = basketTopZ - basketBotZ;
const basketTopHalf = 3.4,
  basketBotHalf = 2.9;
const basketProfile = CrossSection.square([basketBotHalf * 2, basketBotHalf * 2], true);
const basket = label(
  basketProfile
  .extrude(basketH, 1, 0, [basketTopHalf / basketBotHalf, basketTopHalf / basketBotHalf])
  .translate([0, 0, basketBotZ]),
  'basket'
);

// ---- Suspension ropes spanning the open gap --------------------------------
function rope(x1, y1, z1, x2, y2, z2) {
  const t = 0.32; // rope thickness (radius)
  const a = Manifold.sphere(t, 8).translate([x1, y1, z1]);
  const b = Manifold.sphere(t, 8).translate([x2, y2, z2]);
  return Manifold.hull([a, b]);
}
const cornerXY = 2.6; // basket top corner offset (inside the flared top)
const attachXY = 3.9; // where ropes meet the envelope flank
const attachZ = 16.5; // envelope radius here ~7.0 -> ropes sink well in to fuse
const basketAttachZ = 6.0; // a unit into the basket rim for solid overlap
const ropes = [
  rope(-cornerXY, -cornerXY, basketAttachZ, -attachXY, -attachXY, attachZ),
  rope(cornerXY, -cornerXY, basketAttachZ, attachXY, -attachXY, attachZ),
  rope(-cornerXY, cornerXY, basketAttachZ, -attachXY, attachXY, attachZ),
  rope(cornerXY, cornerXY, basketAttachZ, attachXY, attachXY, attachZ),
].map(r => label(r, 'rope'));

return Manifold.union([envelope, mouthRing, burner, basket, ...ropes]);
